// Strategy
// --------
// The ensures is `LHS ==> det_equal`, where LHS is the conjunction of
// both runs' ensures.  z3 returned `unknown` because the open spec
// `SingleDelivery::receive(pre@, postK@, ...)` carries two distinct
// terms (one for `post1_self_@`, one for `post2_self_@`) whose internal
// `valid()` foralls only trigger on the run-specific `send_state@`, so
// the two are never instantiated in tandem.
//
// We close the gap as in the prompt's example: wrap the obligation in
// `assert(LHS ==> det_equal) by { if LHS { ... } }` to bring all
// 10 ensures-conjuncts (across both runs) into the proof context, then
// case-split on the concrete `pkt.msg`.  In each branch the open spec
// `SingleDelivery::receive` reduces to a single sub-spec which pins the
// abstract post-state to a *function of* `(pre_self_@, pkt@)`, so the
// two runs' post views become `=~=` equal.  The result variant of
// r1 / r2 is forced via the contradiction between an Ack-result's empty
// `get_abstracted_ack_set()` and a Fresh/DuplicatePacket's singleton
// set (i.e. `set!{ack@}` cannot be empty, since it contains `ack@`).
//
// Every assert below is something Verus must discharge — no `assume`,
// no `admit`, no body-less specs.
assert(({
    &&& (post1_self_.valid())
    &&& (r1.valid_ack(pkt))
    &&& (SingleDelivery::receive(pre_self_@, post1_self_@, pkt@, r1.get_ack()@, r1.get_abstracted_ack_set()))
    &&& (r1 is FreshPacket ==> SingleDelivery::new_single_message(pre_self_@, pkt@))
    &&& (r1 is DuplicatePacket ==> !SingleDelivery::new_single_message(pre_self_@, pkt@))
    &&& (post2_self_.valid())
    &&& (r2.valid_ack(pkt))
    &&& (SingleDelivery::receive(pre_self_@, post2_self_@, pkt@, r2.get_ack()@, r2.get_abstracted_ack_set()))
    &&& (r2 is FreshPacket ==> SingleDelivery::new_single_message(pre_self_@, pkt@))
    &&& (r2 is DuplicatePacket ==> !SingleDelivery::new_single_message(pre_self_@, pkt@))
}) ==> det_receive_impl_equal(r1, r2, post1_self_, post2_self_)) by {
    if post1_self_.valid() && r1.valid_ack(pkt)
        && SingleDelivery::receive(pre_self_@, post1_self_@, pkt@, r1.get_ack()@, r1.get_abstracted_ack_set())
        && (r1 is FreshPacket ==> SingleDelivery::new_single_message(pre_self_@, pkt@))
        && (r1 is DuplicatePacket ==> !SingleDelivery::new_single_message(pre_self_@, pkt@))
        && post2_self_.valid() && r2.valid_ack(pkt)
        && SingleDelivery::receive(pre_self_@, post2_self_@, pkt@, r2.get_ack()@, r2.get_abstracted_ack_set())
        && (r2 is FreshPacket ==> SingleDelivery::new_single_message(pre_self_@, pkt@))
        && (r2 is DuplicatePacket ==> !SingleDelivery::new_single_message(pre_self_@, pkt@))
    {
        // Concrete-to-abstract variant bridge: `CSingleMessage::view`
        // is the open spec that translates the tag.
        match pkt.msg {
            CSingleMessage::Ack { .. } => {
                assert(pkt@.msg is Ack);
                // receive_ack forces the acks set to be empty for both runs.
                assert(r1.get_abstracted_ack_set().is_empty());
                assert(r2.get_abstracted_ack_set().is_empty());
                // Singleton-vs-empty contradiction rules out Fresh/Dup.
                if r1 is FreshPacket {
                    assert(r1.get_abstracted_ack_set() =~= set!{r1.get_ack()@});
                    assert(set!{r1.get_ack()@}.contains(r1.get_ack()@));
                    assert(false);
                }
                if r1 is DuplicatePacket {
                    assert(r1.get_abstracted_ack_set() =~= set!{r1.get_ack()@});
                    assert(set!{r1.get_ack()@}.contains(r1.get_ack()@));
                    assert(false);
                }
                if r2 is FreshPacket {
                    assert(r2.get_abstracted_ack_set() =~= set!{r2.get_ack()@});
                    assert(set!{r2.get_ack()@}.contains(r2.get_ack()@));
                    assert(false);
                }
                if r2 is DuplicatePacket {
                    assert(r2.get_abstracted_ack_set() =~= set!{r2.get_ack()@});
                    assert(set!{r2.get_ack()@}.contains(r2.get_ack()@));
                    assert(false);
                }
                // r1, r2 are both AckOrInvalid -> result-variant tags agree.

                // Abstract send_state pinned to a function of (pre@, pkt@).
                let old_ack = ack_state_lookup(pkt@.src, pre_self_@.send_state);
                let ack_seqno = pkt@.msg.arrow_Ack_ack_seqno();
                if ack_seqno > old_ack.num_packets_acked {
                    let new_ack = AckState::<Message> {
                        num_packets_acked: ack_seqno,
                        un_acked: truncate_un_ack_list(old_ack.un_acked, ack_seqno),
                    };
                    let tgt_send = pre_self_@.send_state.insert(pkt@.src, new_ack);
                    assert(post1_self_@.send_state =~= tgt_send);
                    assert(post2_self_@.send_state =~= tgt_send);
                    // NB receive_ack's body writes `..post` (not `..pre`),
                    // so post.receive_state is unconstrained in this
                    // branch -- this is the residual spec-level gap.
                } else {
                    assert(post1_self_@ == pre_self_@);
                    assert(post2_self_@ == pre_self_@);
                }
            }
            CSingleMessage::Message { .. } => {
                assert(pkt@.msg is Message);
                // receive_real_packet pins both runs' abstract receive_state
                // and send_state, then maybe_ack_packet pins the ack set.
                if pre_self_@.new_single_message(pkt@) {
                    let last = tombstone_table_lookup(pkt@.src, pre_self_@.receive_state);
                    let tgt_recv = pre_self_@.receive_state.insert(pkt@.src, (last + 1) as nat);
                    assert(post1_self_@.receive_state =~= tgt_recv);
                    assert(post2_self_@.receive_state =~= tgt_recv);
                    assert(post1_self_@.send_state =~= pre_self_@.send_state);
                    assert(post2_self_@.send_state =~= pre_self_@.send_state);

                    // post.last_seqno(pkt.src) == last+1 == pkt.seqno, so
                    // should_ack_single_message(pkt) holds, so the acks set
                    // is a singleton -- this rules out AckOrInvalid.
                    assert(post1_self_@.should_ack_single_message(pkt@));
                    assert(post2_self_@.should_ack_single_message(pkt@));
                    if r1 is AckOrInvalid {
                        assert(r1.get_abstracted_ack_set().is_empty());
                        assert(post1_self_@.send_ack(pkt@, r1.get_ack()@, r1.get_abstracted_ack_set()));
                        assert(r1.get_abstracted_ack_set() =~= set!{r1.get_ack()@});
                        assert(set!{r1.get_ack()@}.contains(r1.get_ack()@));
                        assert(false);
                    }
                    if r1 is DuplicatePacket { assert(false); }
                    if r2 is AckOrInvalid {
                        assert(r2.get_abstracted_ack_set().is_empty());
                        assert(post2_self_@.send_ack(pkt@, r2.get_ack()@, r2.get_abstracted_ack_set()));
                        assert(r2.get_abstracted_ack_set() =~= set!{r2.get_ack()@});
                        assert(set!{r2.get_ack()@}.contains(r2.get_ack()@));
                        assert(false);
                    }
                    if r2 is DuplicatePacket { assert(false); }
                    // r1, r2 both FreshPacket.
                } else {
                    assert(post1_self_@ == pre_self_@);
                    assert(post2_self_@ == pre_self_@);
                    if r1 is FreshPacket { assert(false); }
                    if r2 is FreshPacket { assert(false); }
                    // Remaining choice is determined by
                    // should_ack_single_message, a function of
                    // (post.receive_state, pkt); identical for both runs.
                    if post1_self_@.should_ack_single_message(pkt@) {
                        if r1 is AckOrInvalid {
                            assert(r1.get_abstracted_ack_set().is_empty());
                            assert(post1_self_@.send_ack(pkt@, r1.get_ack()@, r1.get_abstracted_ack_set()));
                            assert(r1.get_abstracted_ack_set() =~= set!{r1.get_ack()@});
                            assert(set!{r1.get_ack()@}.contains(r1.get_ack()@));
                            assert(false);
                        }
                        if r2 is AckOrInvalid {
                            assert(r2.get_abstracted_ack_set().is_empty());
                            assert(post2_self_@.send_ack(pkt@, r2.get_ack()@, r2.get_abstracted_ack_set()));
                            assert(r2.get_abstracted_ack_set() =~= set!{r2.get_ack()@});
                            assert(set!{r2.get_ack()@}.contains(r2.get_ack()@));
                            assert(false);
                        }
                        // r1, r2 both DuplicatePacket.
                    } else {
                        if r1 is DuplicatePacket {
                            assert(r1.get_abstracted_ack_set() =~= set!{r1.get_ack()@});
                            assert(set!{r1.get_ack()@}.contains(r1.get_ack()@));
                            assert(r1.get_abstracted_ack_set().is_empty());
                            assert(false);
                        }
                        if r2 is DuplicatePacket {
                            assert(r2.get_abstracted_ack_set() =~= set!{r2.get_ack()@});
                            assert(set!{r2.get_ack()@}.contains(r2.get_ack()@));
                            assert(r2.get_abstracted_ack_set().is_empty());
                            assert(false);
                        }
                        // r1, r2 both AckOrInvalid.
                    }
                }
            }
            CSingleMessage::InvalidMessage { .. } => {
                assert(pkt@.msg is InvalidMessage);
                assert(post1_self_@ == pre_self_@);
                assert(post2_self_@ == pre_self_@);
                assert(r1.get_abstracted_ack_set() =~= Set::<Packet>::empty());
                assert(r2.get_abstracted_ack_set() =~= Set::<Packet>::empty());
                if r1 is FreshPacket {
                    assert(r1.get_abstracted_ack_set() =~= set!{r1.get_ack()@});
                    assert(set!{r1.get_ack()@}.contains(r1.get_ack()@));
                    assert(false);
                }
                if r1 is DuplicatePacket {
                    assert(r1.get_abstracted_ack_set() =~= set!{r1.get_ack()@});
                    assert(set!{r1.get_ack()@}.contains(r1.get_ack()@));
                    assert(false);
                }
                if r2 is FreshPacket {
                    assert(r2.get_abstracted_ack_set() =~= set!{r2.get_ack()@});
                    assert(set!{r2.get_ack()@}.contains(r2.get_ack()@));
                    assert(false);
                }
                if r2 is DuplicatePacket {
                    assert(r2.get_abstracted_ack_set() =~= set!{r2.get_ack()@});
                    assert(set!{r2.get_ack()@}.contains(r2.get_ack()@));
                    assert(false);
                }
                // r1, r2 both AckOrInvalid.
            }
        }
        // Lift to whole-view extensional equality.
        assert(post1_self_@.send_state =~= post2_self_@.send_state);
        assert(post1_self_@.receive_state =~= post2_self_@.receive_state);
        // Final obligations of `det_receive_impl_equal` are concrete
        // `HashMap == HashMap`.  `HashMap<V>` is `external_body` with an
        // `uninterp spec view`, so no sound prelude can lift abstract-Map
        // view equality to opaque-HashMap equality.  We assert the
        // residual obligations so the determinism gap surfaces directly
        // rather than being hidden under a generic `unknown`.
        assert(post1_self_.receive_state.epmap == post2_self_.receive_state.epmap);
        assert(post1_self_.send_state.epmap == post2_self_.send_state.epmap);
    }
};
